337→/// Join spawned parallel futures into their slots, handling panics.
338→async fn join_spawned_futures(
339→    futures: Vec<(usize, tokio::task::JoinHandle<ContentBlock>)>,
340→    slots: &mut [Option<ContentBlock>],
341→    tool_ids: &[(String, String, serde_json::Value)],
342→) {
343→    let handles: Vec<_> = futures
344→        .into_iter()
345→        .map(|(idx, h)| async move { (idx, h.await) })
346→        .collect();
347→    for (idx, result) in futures_util::future::join_all(handles).await {
348→        slots[idx] = Some(match result {
349→            Ok(block) => block,
350→            Err(_) => ContentBlock::ToolResult {
351→                tool_use_id: tool_ids[idx].0.clone(),
352→                content: "tool panicked".to_string(),
353→                is_error: Some(true),
354→            },
355→        });
356→    }
357→}
