511→#[allow(clippy::too_many_arguments)]
512→async fn run_turn(
513→    cli: &Cli,
514→    client: &AnthropicClient,
515→    system_prompt: &str,
516→    tools: &[serde_json::Value],
517→    conversation: &mut Vec<Message>,
518→    session: &mut SessionWriter,
519→    hooks: &HookRunner,
520→    input: &str,
521→) {
522→    let user_msg = Message {
523→        role: "user".to_string(),
524→        content: vec![ContentBlock::Text {
525→            text: input.to_string(),
526→        }],
527→    };
528→    conversation.push(user_msg.clone());
529→    session.append_user_turn(&user_msg);
530→    session.write_prompt(input);
531→
532→    let mut tool_iterations: usize = 0;
533→    let mut continuation_count: usize = 0;
534→    let mut last_input_tokens: u64 = 0;
535→    let mut consecutive_block_count: usize = 0;
536→    let mut total_block_count: usize = 0;
537→    let mut total_tokens: u64 = 0;
538→    let mut stop_reason_str = "end_turn";
539→
540→    loop {
541→        trim_if_needed(conversation, last_input_tokens);
542→
543→        if tool_iterations >= MAX_TOOL_ITERATIONS {
544→            eprintln!("[warn] Tool iteration limit ({MAX_TOOL_ITERATIONS}) reached");
545→            recover_conversation(conversation);
546→            stop_reason_str = "iteration_limit";
547→            break;
548→        }
549→
550→        // Retry loop: attempt 0 = initial call, 1..=MAX_RETRIES = retries
551→        let mut api_result = None;
552→        #[allow(clippy::needless_range_loop)]
553→        for attempt in 0..=MAX_RETRIES {
554→            let result = client
555→                .send_message(
556→                    &cli.model,
557→                    cli.max_tokens,
558→                    system_prompt,
559→                    conversation,
560→                    tools,
561→                    &mut |text| {
562→                        print!("{text}");
563→                        io::stdout().flush().ok();
564→                    },
565→                )
566→                .await;
567→
568→            match result {
569→                Ok(r) => {
570→                    api_result = Some(r);
571→                    break;
572→                }
573→                Err(e) => {
574→                    eprintln!("\n[error] API call failed: {e}");
575→                    if classify_error(&e) == ErrorClass::Permanent {
576→                        recover_conversation(conversation);
577→                        stop_reason_str = "api_error";
578→                        break;
579→                    }
580→                    if attempt >= MAX_RETRIES {
581→                        eprintln!("[retry] Max retries ({MAX_RETRIES}) exhausted");
582→                        recover_conversation(conversation);
583→                        stop_reason_str = "api_error";
584→                        break;
585→                    }
586→                    let delay = if let AgentError::HttpError {
587→                        retry_after: Some(ra),
588→                        ..
589→                    } = &e
590→                    {
591→                        let capped = (*ra).min(RETRY_AFTER_CAP);
592→                        eprintln!("[retry] Using retry-after: {capped}s");
593→                        capped
594→                    } else {
595→                        BACKOFF_SCHEDULE[attempt]
596→                    };
597→                    if matches!(e, AgentError::StreamTransient(_)) {
598→                        eprintln!("[retry] Retrying from beginning of response...");
599→                    }
600→                    eprintln!(
601→                        "[retry] Attempt {}/{MAX_RETRIES}: {} — waiting {delay}s",
602→                        attempt + 1,
603→                        e
604→                    );
605→                    tokio::time::sleep(std::time::Duration::from_secs(delay)).await;
606→                }
607→            }
608→        }
609→
610→        let (blocks, stop_reason, usage) = match api_result {
611→            Some(r) => r,
612→            None => break,
613→        };
614→
615→        last_input_tokens = usage.input_tokens;
616→        total_tokens += usage.input_tokens + usage.output_tokens;
617→        if cli.verbose {
618→            eprintln!(
619→                "[verbose] Cache: {} read, {} created, {} total input",
620→                usage.cache_read_input_tokens,
621→                usage.cache_creation_input_tokens,
622→                usage.input_tokens
623→            );
624→        }
625→
626→        let blocks = if stop_reason == StopReason::MaxTokens {
627→            filter_null_input_tool_use(blocks)
628→        } else {
629→            blocks
630→        };
631→
632→        let assistant_msg = Message {
633→            role: "assistant".to_string(),
634→            content: blocks.clone(),
635→        };
636→        conversation.push(assistant_msg.clone());
637→        session.append_assistant_turn(&assistant_msg, &usage);
638→
639→        // EndTurn — normal completion
640→        if stop_reason == StopReason::EndTurn {
641→            println!();
642→            stop_reason_str = "end_turn";
643→            break;
644→        }
645→
646→        // MaxTokens — decide: continue, dispatch tools, or break
647→        if stop_reason == StopReason::MaxTokens {
648→            println!();
649→
650→            match classify_max_tokens(&blocks, continuation_count) {
651→                MaxTokensAction::BreakEmpty => {
652→                    eprintln!("[info] Empty response at max_tokens, breaking");
653→                    stop_reason_str = "continuation_cap";
654→                    break;
655→                }
656→                MaxTokensAction::DispatchTools => {} // Fall through to tool dispatch
657→                MaxTokensAction::Continue => {
658→                    continuation_count += 1;
659→                    eprintln!(
660→                        "[continue] Response truncated at max_tokens, requesting continuation ({}/{})",
661→                        continuation_count, MAX_CONTINUATIONS
662→                    );
663→                    let cont_msg = Message {
664→                        role: "user".to_string(),
665→                        content: vec![ContentBlock::Text {
666→                            text: "Continue from where you left off.".to_string(),
667→                        }],
668→                    };
669→                    conversation.push(cont_msg.clone());
670→                    session.append_user_turn(&cont_msg);
671→                    continue;
672→                }
673→                MaxTokensAction::BreakCapReached => {
674→                    eprintln!("[continue] Max continuations reached, breaking");
675→                    stop_reason_str = "continuation_cap";
676→                    break;
677→                }
678→            }
679→        }
680→
681→        // Tool dispatch — runs for both ToolUse and MaxTokens-with-valid-tools
682→        let tool_uses: Vec<_> = blocks
683→            .iter()
684→            .filter_map(|b| match b {
685→                ContentBlock::ToolUse { id, name, input } => {
686→                    Some((id.clone(), name.clone(), input.clone()))
687→                }
688→                _ => None,
689→            })
690→            .collect();
691→        let all_pure = !tool_uses.is_empty()
692→            && tool_uses
693→                .iter()
694→                .all(|(_, name, _)| tool_effect(name) == ToolEffect::Pure);
695→
696→        let mut signal_break = false;
697→        let mut threshold_tripped = false;
698→        let mut threshold_reason = "";
