 874→const MAX_CONTINUATIONS: usize = 3;
 875→
 876→/// Determine what to do after a MaxTokens stop_reason.
 877→/// Returns the action to take given the filtered content blocks and current continuation count.
 878→#[derive(Debug, PartialEq)]
 879→enum MaxTokensAction {
 880→    /// Response was empty (only placeholder) — break immediately
 881→    BreakEmpty,
 882→    /// Valid tool_use blocks present — fall through to tool dispatch
 883→    DispatchTools,
 884→    /// Text-only, under cap — inject continuation prompt
 885→    Continue,
 886→    /// Text-only, cap reached — break
 887→    BreakCapReached,
 888→}
 889→
 890→fn classify_max_tokens(blocks: &[ContentBlock], continuation_count: usize) -> MaxTokensAction {
 891→    // Check for empty response (only the "[Response truncated]" placeholder)
 892→    let is_empty = blocks.len() == 1
 893→        && matches!(&blocks[0], ContentBlock::Text { text } if text == "[Response truncated]");
 894→    if is_empty {
 895→        return MaxTokensAction::BreakEmpty;
 896→    }
 897→
 898→    let has_valid_tools = blocks
 899→        .iter()
 900→        .any(|b| matches!(b, ContentBlock::ToolUse { .. }));
 901→
 902→    if has_valid_tools {
 903→        MaxTokensAction::DispatchTools
 904→    } else if continuation_count < MAX_CONTINUATIONS {
 905→        MaxTokensAction::Continue
 906→    } else {
 907→        MaxTokensAction::BreakCapReached
 908→    }
 909→}
