        let mut msgs = vec![
            Message {
                role: "user".to_string(),
                content: vec![ContentBlock::Text {
                    text: "hello".to_string(),
                }],
            },
            Message {
                role: "assistant".to_string(),
                content: vec![ContentBlock::Text {
                    text: "hi".to_string(),
                }],
            },
        ];
        let original_len = msgs.len();
        trim_conversation(&mut msgs);
        assert_eq!(msgs.len(), original_len);
    }

