            "tu_1",
            "Bash",
            &serde_json::Value::Null,
            0,
            &mut consecutive,
            &mut total,
        )
        .await;
        match result {
            PreDispatchResult::Blocked(ContentBlock::ToolResult {
                tool_use_id,
                content,
                is_error,
            }) => {
                assert_eq!(tool_use_id, "tu_1");
                assert!(content.contains("null input"));
                assert_eq!(is_error, Some(true));
            }
